import{_ as t,o as i,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"03. Information Required For Letter Of Appointment","description":"","frontmatter":{"title":"03. Information Required For Letter Of Appointment","eba":"Nurses and Midwives 2024-2028","topics":["appendices","employment"]},"headers":[],"relativePath":"ebas/nurses-midwives/appendices/03-information-required-for-letter-of-appointment.md","filePath":"ebas/nurses-midwives/appendices/03-information-required-for-letter-of-appointment.md"}'),r={name:"ebas/nurses-midwives/appendices/03-information-required-for-letter-of-appointment.md"};function a(p,e,l,s,m,d){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_03-information-required-for-letter-of-appointment" tabindex="-1">03. Information Required For Letter Of Appointment <a class="header-anchor" href="#_03-information-required-for-letter-of-appointment" aria-label="Permalink to &quot;03. Information Required For Letter Of Appointment&quot;">​</a></h1><p>Formatting note</p><p>The appendix body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find appendices by their title, number, topic or synonyms.</p><p>```text – INFORMATION REQUIRED FOR LETTER OF APPOINTMENT</p><p>The letter of appointment will contain the following information: 1. Name of Employer.</p><ol><li><p>Employee&#39;s classification, position title, and Level.</p></li><li><p>The workplace/Campus/location where the person is to be situated.</p></li><li><p>The name of the enterprise agreement which contains their terms and conditions of employment.</p></li><li><p>Their mode of employment i.e. whether full-time, part-time, fixed term, casual or bank Employee. Where the employment is on a fixed term basis, the rationale for the fixed term engagement.</p></li><li><p>Specify that employment is ongoing unless a valid fixed term appointment is proposed.</p></li><li><p>Fortnightly hours will be [insert] and for part-timers (by mutual agreement) additional shifts may be added. Shifts will be worked in accordance with roster. Payment of additional shifts will not be at casual rates. If you agree to work regular additional shifts your letter of appointment will be varied accordingly.</p></li><li><p>Date of commencement.</p></li><li><p>Acknowledgment (where applicable) of prior service/entitlements to personal leave, long service, etc. (where known and available).</p></li><li><p>Other information as required depending on the nature of the position.</p></li><li><p>Relevant qualifications and allowances payable.</p></li></ol><p>Appendix 3 – Information Required for Letter of Appointment 245 ```</p>',7)])])}const h=t(r,[["render",a]]);export{c as __pageData,h as default};
